SET search_path TO core; CREATE TABLE IF NOT EXISTS professional_enquiries (id UUID PRIMARY KEY, vendor_id UUID NOT NULL, sender_id UUID, sender_name VARCHAR(255) NOT NULL, sender_email VARCHAR(255) NOT NULL, message TEXT NOT NULL, status VARCHAR(50) NOT NULL); ALTER TABLE professional_enquiries ADD COLUMN IF NOT EXISTS deleted BOOLEAN NOT NULL DEFAULT FALSE, ADD COLUMN IF NOT EXISTS created_at TIMESTAMP, ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP; UPDATE professional_enquiries SET created_at = COALESCE(created_at, now()), updated_at = COALESCE(updated_at, now()) WHERE created_at IS NULL OR updated_at IS NULL;
